sql:
SELECT warehouse_id, SUM(quantity) AS total_quantity
FROM inventories
GROUP BY warehouse_id;

external_knowledge:
- 'Admin%' refers to usernames starting with the word 'Admin';
- 'shipped' status means the order has been dispatched from the warehouse;
- 'PayPal' indicates payment made via PayPal;
- 'common sizes' refer to standard sizes like XS, S, M, L;
- 'overseen by administrative personnel' means the user is an admin managing the product;
- 'sizes are specified in IT, US, UK, and FR regions' means positive values in columns for IT, US, UK, and FR sizes.

sql:
SELECT u.user_name
FROM users u
WHERE u.user_id NOT IN (
  SELECT o.customer_id
  FROM orders o
);
